          name: "gcc",
          executable: "gcc",
          args: ["--version"],
          regex: "(?P<version>(?P<major>\\d+)\\.(?P<minor>\\d+)\\.(?P<patch>\\d+))",
        },
      ],
    },
  }}
/>

### Odin

This example reproduces an [Odin][odin] version segment purely through configuration.

<Config
  data={{
    type: "language",
    style: "plain",
    template: "{{ if .Error }}{{ else }}  {{ .Full }}{{ end }}",
    options: {
      name: "odin",
      extensions: ["*.odin"],
      project_files: ["ols.json"],
